class Solution {
    public int getKth(int lo, int hi, int k) {
        int[][] arr = new int[hi - lo + 1][2];
        for (int i = lo; i <= hi; i++) {
            arr[i - lo][0] = i;
            arr[i - lo][1] = power(i);
        }
        java.util.Arrays.sort(arr, (a, b) -> a[1] == b[1] ? a[0] - b[0] : a[1] - b[1]);
        return arr[k - 1][0];
    }

    private int power(int x) {
        int steps = 0;
        while (x != 1) {
            if ((x & 1) == 0) x >>= 1;
            else x = 3 * x + 1;
            steps++;
        }
        return steps;
    }
}
```
